               ['off',0,binToX(n,s.off[0])],['off',1,binToX(n,s.off[1])]];
  let best=null,bd=14;
  cands.forEach(([k,e,px])=>{const dd=Math.abs(px-x); if(dd<bd){bd=dd;best={kind:k,edge:e};}});
